import React, { useState, useEffect, useRef } from 'react';
import {
  Container,
  Box,
  Typography,
  TextField,
  Button,
  Card,
  CardContent,
  List,
  ListItem,
  ListItemAvatar,
  ListItemText,
  Avatar,
  Divider,
  Badge,
  IconButton,
  CircularProgress
} from '@mui/material';
import {
  Send as SendIcon,
  Person as PersonIcon
} from '@mui/icons-material';
import { useChat } from '../context/ChatContext';

const Chat = () => {
  const { conversations, activeConversation, setActiveConversation, sendMessage, loading } = useChat();
  const [newMessage, setNewMessage] = useState('');
  const messagesEndRef = useRef(null);

  const handleSendMessage = () => {
    if (newMessage.trim() && activeConversation) {
      sendMessage(activeConversation.id, newMessage);
      setNewMessage('');
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  // Scroll to bottom of messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [activeConversation?.messages]);

  if (loading) {
    return (
      <Container maxWidth="lg">
        <Box sx={{ 
          display: 'flex', 
          justifyContent: 'center', 
          alignItems: 'center', 
          height: '60vh' 
        }}>
          <CircularProgress sx={{ color: '#008080' }} />
        </Box>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Typography 
          variant="h4" 
          sx={{ 
            fontWeight: 700, 
            color: '#008080',
            mb: 3,
            textAlign: 'center'
          }}
        >
          Messages
        </Typography>

        <Card sx={{ 
          borderRadius: '16px', 
          boxShadow: '0 4px 12px rgba(0, 128, 128, 0.1)',
          height: '70vh',
          display: 'flex'
        }}>
          {/* Conversations List */}
          <Box sx={{ 
            width: '35%', 
            borderRight: '1px solid #E0E0E0',
            display: 'flex',
            flexDirection: 'column'
          }}>
            <CardContent sx={{ 
              p: 2, 
              pb: '16px !important',
              borderBottom: '1px solid #E0E0E0'
            }}>
              <Typography variant="h6" sx={{ fontWeight: 600, color: '#008080' }}>
                Conversations
              </Typography>
            </CardContent>

            <Box sx={{ flexGrow: 1, overflow: 'auto' }}>
              <List sx={{ p: 0 }}>
                {conversations.map(conversation => (
                  <ListItem 
                    key={conversation.id}
                    button
                    onClick={() => setActiveConversation(conversation)}
                    sx={{ 
                      borderBottom: '1px solid #F0F0F0',
                      backgroundColor: activeConversation?.id === conversation.id ? '#E0F7F7' : 'transparent',
                      '&:hover': {
                        backgroundColor: activeConversation?.id === conversation.id ? '#E0F7F7' : '#F5F5F5'
                      }
                    }}
                  >
                    <ListItemAvatar>
                      <Badge 
                        badgeContent={conversation.unreadCount} 
                        color="primary"
                        sx={{ 
                          '& .MuiBadge-badge': {
                            backgroundColor: '#008080'
                          }
                        }}
                      >
                        <Avatar>
                          <PersonIcon />
                        </Avatar>
                      </Badge>
                    </ListItemAvatar>
                    <ListItemText 
                      primary={conversation.user.name}
                      secondary={conversation.lastMessage.text}
                      primaryTypographyProps={{ 
                        fontWeight: conversation.unreadCount > 0 ? 600 : 400,
                        color: '#0C1F26'
                      }}
                      secondaryTypographyProps={{ 
                        noWrap: true,
                        color: '#5A7D8C'
                      }}
                    />
                    <Typography variant="caption" color="text.secondary">
                      {conversation.lastMessage.time}
                    </Typography>
                  </ListItem>
                ))}
              </List>
            </Box>
          </Box>

          {/* Chat Window */}
          <Box sx={{ 
            width: '65%', 
            display: 'flex',
            flexDirection: 'column'
          }}>
            {activeConversation ? (
              <>
                <CardContent sx={{ 
                  p: 2, 
                  pb: '16px !important',
                  borderBottom: '1px solid #E0E0E0'
                }}>
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <Avatar sx={{ mr: 2 }}>
                      <PersonIcon />
                    </Avatar>
                    <Box>
                      <Typography variant="h6" sx={{ fontWeight: 600, color: '#008080' }}>
                        {activeConversation.user.name}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        Online
                      </Typography>
                    </Box>
                  </Box>
                </CardContent>

                <Box sx={{ 
                  flexGrow: 1, 
                  p: 2, 
                  overflow: 'auto',
                  display: 'flex',
                  flexDirection: 'column'
                }}>
                  <List sx={{ flexGrow: 1 }}>
                    {activeConversation.messages.map(message => (
                      <ListItem 
                        key={message.id}
                        sx={{ 
                          justifyContent: message.fromMe ? 'flex-end' : 'flex-start',
                          flexDirection: 'column',
                          alignItems: message.fromMe ? 'flex-end' : 'flex-start',
                          pl: 0,
                          pr: 0
                        }}
                      >
                        <Box sx={{ 
                          backgroundColor: message.fromMe ? '#008080' : '#F0F0F0',
                          color: message.fromMe ? 'white' : '#0C1F26',
                          borderRadius: '12px',
                          p: 1.5,
                          maxWidth: '70%',
                          mb: 1
                        }}>
                          <Typography variant="body1">
                            {message.text}
                          </Typography>
                        </Box>
                        <Typography variant="caption" color="text.secondary">
                          {message.time}
                        </Typography>
                      </ListItem>
                    ))}
                    <div ref={messagesEndRef} />
                  </List>
                </Box>

                <Box sx={{ 
                  p: 2, 
                  borderTop: '1px solid #E0E0E0',
                  display: 'flex'
                }}>
                  <TextField
                    fullWidth
                    multiline
                    maxRows={4}
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    onKeyPress={handleKeyPress}
                    placeholder="Type a message..."
                    variant="outlined"
                    sx={{ 
                      mr: 1,
                      '& .MuiOutlinedInput-root': {
                        borderRadius: '24px',
                        backgroundColor: '#F4F9F9'
                      }
                    }}
                  />
                  <IconButton 
                    onClick={handleSendMessage}
                    sx={{ 
                      backgroundColor: '#008080',
                      color: 'white',
                      width: '48px',
                      height: '48px',
                      '&:hover': {
                        backgroundColor: '#006666'
                      }
                    }}
                  >
                    <SendIcon />
                  </IconButton>
                </Box>
              </>
            ) : (
              <Box sx={{ 
                display: 'flex', 
                justifyContent: 'center', 
                alignItems: 'center', 
                height: '100%' 
              }}>
                <Typography variant="h6" color="text.secondary">
                  Select a conversation to start chatting
                </Typography>
              </Box>
            )}
          </Box>
        </Card>
      </Box>
    </Container>
  );
};

export default Chat;
